import React, { useRef, useEffect } from "react";
import { getImage } from "../../utils/getImage";

export default function Lightbox({
  selected,
  isOpen,
  onClose,
  onNext,
  onPrev,
  isMobile,
  zoom,
  setZoom,
}) {
  const lightboxRef = useRef(null);
  const touchStartX = useRef(0);
  const touchEndX = useRef(0);

  // Focus trap
  useEffect(() => {
    if (isOpen && lightboxRef.current) {
      lightboxRef.current.focus();
    }
  }, [isOpen]);

  // Swipe handlers
  const handleTouchStart = (e) => {
    touchStartX.current = e.touches[0].clientX;
  };

  const handleTouchMove = (e) => {
    touchEndX.current = e.touches[0].clientX;
  };

  const handleTouchEnd = () => {
    const diff = touchStartX.current - touchEndX.current;
    const threshold = 50;

    if (Math.abs(diff) > threshold) {
      if (diff > 0) {
        onNext();
      } else {
        onPrev();
      }
    }

    touchStartX.current = 0;
    touchEndX.current = 0;
  };

  if (!isOpen || !selected) return null;

  return (
    <div
      ref={lightboxRef}
      role="dialog"
      aria-modal="true"
      aria-label={`Vista ampliada de ${selected.titulo}`}
      tabIndex={-1}
      onClick={onClose}
      onTouchStart={handleTouchStart}
      onTouchMove={handleTouchMove}
      onTouchEnd={handleTouchEnd}
      style={{
        position: "fixed",
        inset: 0,
        background: "rgba(0,0,0,0.96)",
        display: "flex",
        flexDirection: "column",
        alignItems: "center",
        justifyContent: "center",
        zIndex: 999,
        touchAction: "pan-y",
      }}
    >
      {/* CONTENEDOR IMAGEN */}
      <div
        style={{
          display: "flex",
          alignItems: "center",
          justifyContent: "center",
          width: "100%",
          flex: 1,
          position: "relative",
          padding: isMobile ? "16px" : "24px",
        }}
      >
        {/* FLECHA IZQUIERDA */}
        <button
          onClick={(e) => {
            e.stopPropagation();
            onPrev();
          }}
          style={arrowStyle("left", isMobile)}
          aria-label="Anterior"
        >
          ‹
        </button>

        {/* IMAGEN */}
        <img
          src={getImage(selected, "full")}
          alt={selected.titulo}
          onClick={(e) => e.stopPropagation()}
          onDoubleClick={(e) => {
            e.stopPropagation();
            setZoom((z) => !z);
          }}
          draggable={false}
          style={{
            maxWidth: isMobile ? "92%" : "75%",
            maxHeight: zoom ? "none" : "85vh",
            borderRadius: "8px",
            transform: zoom ? "scale(1.6)" : "scale(1)",
            transition: "transform 0.3s ease",
            cursor: zoom ? "zoom-out" : "zoom-in",
            userSelect: "none",
            pointerEvents: "auto",
            boxShadow: "0 20px 60px rgba(0,0,0,0.4)",
          }}
        />

        {/* FLECHA DERECHA */}
        <button
          onClick={(e) => {
            e.stopPropagation();
            onNext();
          }}
          style={arrowStyle("right", isMobile)}
          aria-label="Siguiente"
        >
          ›
        </button>
      </div>

      {/* FOOTER CON TÍTULO + DESCARGA */}
<div
  style={{
    width: "100%",
    padding: isMobile ? "14px 16px" : "16px 24px",
    background: "rgba(0,0,0,0.7)",
    color: "#ffffff",
    textAlign: "center",
    borderTop: "1px solid rgba(255,255,255,0.08)",
  }}
>
  <h3
    style={{
      margin: "0 0 4px",
      fontSize: isMobile ? "15px" : "18px",
      fontWeight: "600",
    }}
  >
    {selected.titulo}
  </h3>

  {/* DESCRIPCIÓN */}
  {selected.descripcion && (
    <p
      style={{
        margin: "0 0 4px",
        fontSize: isMobile ? "12px" : "14px",
        fontWeight: "300",
        opacity: 0.7,
      }}
    >
      {selected.descripcion}
    </p>
  )}

  {/* ORIGEN · BASADO_EN */}
  {(selected.creditos?.origen || selected.creditos?.basado_en) && (
    <p
      style={{
        margin: "0 0 12px",
        fontSize: "11px",
        fontWeight: "300",
        fontStyle: "italic",
        opacity: 0.55,
      }}
    >
      {selected.creditos?.origen === "original" ? "Original" : 
       selected.creditos?.origen === "adaptado" ? "Adaptado" : 
       selected.creditos?.origen}
      {selected.creditos?.origen && selected.creditos?.basado_en && " · "}
      {selected.creditos?.basado_en && `De: ${selected.creditos.basado_en}`}
    </p>
  )}

  {/* BOTÓN DESCARGAR */}
  <a
    href={getImage(selected, "full")}
    download={`${selected.titulo}.png`}
    onClick={(e) => e.stopPropagation()}
    style={{
      display: "inline-block",
      padding: "7px 18px",
      borderRadius: "6px",
      border: "1px solid rgba(255,255,255,0.3)",
      background: "transparent",
      color: "#ffffff",
      fontSize: "12px",
      fontWeight: "500",
      textDecoration: "none",
      cursor: "pointer",
      transition: "all 0.2s ease",
    }}
    onMouseEnter={(e) => {
      e.currentTarget.style.background = "rgba(255,255,255,0.12)";
      e.currentTarget.style.borderColor = "rgba(255,255,255,0.5)";
    }}
    onMouseLeave={(e) => {
      e.currentTarget.style.background = "transparent";
      e.currentTarget.style.borderColor = "rgba(255,255,255,0.3)";
    }}
  >
    Descargar
  </a>
</div>
    </div>
  );
}

function arrowStyle(side, isMobile) {
  return {
    position: "absolute",
    [side]: isMobile ? "4px" : "16px",
    top: "50%",
    transform: "translateY(-50%)",
    width: isMobile ? "36px" : "48px",
    height: isMobile ? "36px" : "48px",
    display: "flex",
    alignItems: "center",
    justifyContent: "center",
    fontSize: isMobile ? "28px" : "36px",
    color: "rgba(255,255,255,0.7)",
    background: "rgba(0,0,0,0.3)",
    border: "none",
    borderRadius: "50%",
    cursor: "pointer",
    zIndex: 10,
    transition: "background 0.2s ease, color 0.2s ease",
  };
}
